export const advanceGameOfLife = (aliveCells: number[][], steps: number): number[][] => {
  if (steps === 0) return aliveCells;

  const aliveSet = new Set(aliveCells.map(([x, y]) => `${x},${y}`));

  return aliveCells.filter(([x, y]) => {
    let neighbors = 0;
    for (let dx = -1; dx <= 1; dx++) {
      for (let dy = -1; dy <= 1; dy++) {
        if (dx === 0 && dy === 0) continue;
        if (aliveSet.has(`${x + dx},${y + dy}`)) neighbors++;
      }
    }
    return neighbors === 2 || neighbors === 3;
  });
};

